// ─── HOOKS ───
function useVis(th=.1){const r=useRef(null);const[v,s]=useState(false);useEffect(()=>{const el=r.current;if(!el)return;const o=new IntersectionObserver(([e])=>{if(e.isIntersecting){s(true);o.disconnect()}},{threshold:th});o.observe(el);return()=>o.disconnect()},[]);return[r,v]}
function Rv({children,delay=0,style:sx={}}){const[r,v]=useVis();return<div ref={r} style={{opacity:v?1:0,transform:v?"translateY(0)":"translateY(22px)",transition:`opacity .6s ease ${delay}s, transform .6s ease ${delay}s`,...sx}}>{children}</div>}

