// APP
// ════════════════════════════════════════
function App(){
  const[page,setPage]=useState("home");
  const[popup,setPopup]=useState(true);

  return<>
    <Nav page={page} go={setPage}/>
    {popup&&<IntroPopup onClose={()=>setPopup(false)} go={setPage}/>}
    <main>{
      page==="home"?<Home go={setPage}/>:
      page==="memberships"?<Memberships go={setPage}/>:
      page==="schedule"?<Schedule/>:
      page==="about"?<About/>:
      page==="events"?<Events go={setPage}/>:
      page==="childcare"?<Childcare go={setPage}/>:
      <Home go={setPage}/>
    }</main>
    <Footer go={setPage}/>
  </>
}

// ─── MOUNT ───
const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(React.createElement(App));
